# -*- coding: UTF-8 -*-
import math

class Solution:
    def solve(self, a: float, b: float, c: float) -> list[float]:
        if a == 0:
            if b == 0:
                return [None, None]
            else:
                return [None, -c / b]
        else:
            discriminant = b ** 2 - 4 * a * c
            if discriminant > 0:
                return [(-b + math.sqrt(discriminant)) / (2 * a), (-b - math.sqrt(discriminant)) / (2 * a)]
            elif discriminant == 0:
                return [(-b) / (2 * a)]
            else:
                root1 = (-b + 1j * math.sqrt(-discriminant)) / (2 * a)
                root2 = (-b - 1j * math.sqrt(-discriminant)) / (2 * a)
                return [root1, root2]

# main function to get input from stdin and output to stdout
def main_func():
    import sys
    input_list = sys.stdin.readline().split()
    a = int(input_list[0])
    b = int(input_list[1])
    c = int(input_list[2])
    solution = Solution()
    output_list = solution.solve(a, b, c)
    if isinstance(output_list[0], complex):
        print(f'{output_list[0].real} {output_list[0].imag:+}i {output_list[1].real} {output_list[1].imag:+}i', end='')
    else:
        print(f'{output_list[0]} {output_list[1]}', end='')

