#include <iostream>
#include <cmath>
using namespace std;
class Solution {
public:
    vector<double> solve(double a, double b, double c) {
        if (a == 0) {
            if (b == 0) return {numeric_limits<double>::quiet_NaN(), numeric_limits<double>::quiet_NaN()};
            else return {-c / b, numeric_limits<double>::quiet_NaN()};
        }
        else {
            double discriminant = b * b - 4 * a * c;
            if (discriminant > 0) {
                return {(-b + sqrt(discriminant)) / (2 * a), (-b - sqrt(discriminant)) / (2 * a)};
            }
            else if (discriminant == 0)
                return {(-b) / (2 * a)};
            else {
                double root1 = (-b + sqrt(-discriminant)) / (2 * a);
                double root2 = (-b - sqrt(-discriminant)) / (2 * a);
                return {root1, root2};
            }
        }
    }
};

